{
  "level": "A2",
  "intro": "W tym temacie nauczysz się, jak tworzyć <strong>Present Simple Passive</strong>: zdania twierdzące, przeczące i pytające w stronie biernej czasu teraźniejszego prostego.",
  "rules": [
    {
      "label": "Wzór",
      "color": "emerald",
      "text": "<strong>am / is / are + V3</strong>:",
      "example": "The letter is written."
    },
    {
      "label": "Przeczenie",
      "color": "rose",
      "text": "<strong>am / is / are + not + V3</strong>:",
      "example": "The letter is not written."
    },
    {
      "label": "Pytanie",
      "color": "blue",
      "text": "<strong>Am / Is / Are + subject + V3?</strong>:",
      "example": "Is the letter written?"
    }
  ]
}

{
  "title": "1. Wybór am / is / are",
  "intro": "Formę <strong>be</strong> dobieramy do podmiotu:",
  "items": [
    {
      "label": "I",
      "title": "am",
      "subtitle": "I am paid monthly."
    },
    {
      "label": "He / She / It",
      "title": "is",
      "subtitle": "It is made in China."
    },
    {
      "label": "You / We / They",
      "title": "are",
      "subtitle": "They are invited to the party."
    },
    {
      "label": "Rzeczowniki w liczbie mnogiej",
      "title": "are",
      "subtitle": "Cars are produced here."
    }
  ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Szyk: <strong>subject + am / is / are + V3 (+ by + agent)</strong>.",
            "examples": [
                {
                    "en": "English is spoken in many countries.",
                    "ua": "W wielu krajach mówi się po angielsku."
                },
                {
                    "en": "The rooms are cleaned every day.",
                    "ua": "Pokoje są sprzątane codziennie."
                },
                {
                    "en": "I am paid at the end of each month.",
                    "ua": "Dostaję wynagrodzenie pod koniec każdego miesiąca."
                }
            ]
        },
        {
            "label": "Kiedy używamy?",
            "color": "sky",
            "description": "Używamy tej formy przy <strong>regularnych czynnościach</strong>, <strong>ogólnych faktach</strong> i <strong>opisach procesów</strong>.",
            "examples": [
                {
                    "en": "Coffee is grown in Brazil.",
                    "ua": "To przykład ogólnego faktu."
                },
                {
                    "en": "Newspapers are delivered every morning.",
                    "ua": "To przykład czynności powtarzalnej."
                },
                {
                    "en": "This road is used by many cars.",
                    "ua": "Skupiamy się na drodze, nie na kierowcach."
                }
            ]
        }
    ]
}

{
    "title": "3. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po am/jest/są: <strong>podmiot + jestem/jest/są + nie + V3</strong>",
            "examples": [
                {
                    "en": "The door is not locked.",
                    "ua": "Drzwi nie są zamknięte."
                },
                {
                    "en": "These cars are not made in Japan.",
                    "ua": "Te maszyny nie są produkowane w Japonii."
                },
                {
                    "en": "I am not invited to the meeting.",
                    "ua": "Nie zostałem zaproszony na spotkanie."
                }
            ]
        },
        {
            "label": "Skrócone formy",
            "color": "amber",
            "description": "<strong>nie jest / nie jest</strong> używane potocznie:",
            "examples": [
                {
                    "en": "The window isn't opened.",
                    "ua": "Okno nie jest otwarte."
                },
                {
                    "en": "The reports aren't finished yet.",
                    "ua": "Raporty nie są jeszcze gotowe."
                }
            ],
            "note": "Forma <strong>nie</strong> nie jest skracana: nie jestem (nie jestem)."
        }
    ]
}

{
    "title":  "4. Zdania pytające",
    "sections":  [
                     {
                         "label":  "Pytania yes/no",
                         "color":  "blue",
                         "description":  "Na górze pojawia się \u003cstrong\u003eAm/Is/Are\u003c/strong\u003e: \u003cstrong\u003eAm/Is/Are + podmiot + V3?\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "Is English spoken here?",
                                              "ua":  "Czy mówią tu po angielsku?"
                                          },
                                          {
                                              "en":  "Are the rooms cleaned daily?",
                                              "ua":  "Czy pokoje są sprzątane codziennie?"
                                          },
                                          {
                                              "en":  "Am I included in the list?",
                                              "ua":  "Czy jestem na liście?"
                                          }
                                      ]
                     },
                     {
                         "label":  "Pytania z wh-",
                         "color":  "sky",
                         "description":  "\u003cstrong\u003eWh-word + am / is / are + subject + V3?\u003c/strong\u003e",
                         "examples":  [
                                          {
                                              "en":  "Where is coffee grown?",
                                              "ua":  "Gdzie uprawia się kawę?"
                                          },
                                          {
                                              "en":  "How often are the rooms cleaned?",
                                              "ua":  "Jak często sprzątane są pokoje?"
                                          },
                                          {
                                              "en":  "Why is this product so popular?",
                                              "ua":  "Dlaczego ten produkt jest tak popularny?"
                                          }
                                      ]
                     },
                     {
                         "label":  "Krótkie odpowiedzi",
                         "color":  "amber",
                         "description":  "Krtkie odpowiedzi maj wzr \u003cstrong\u003eYes / No + subject pronoun + am / is / are\u003c/strong\u003e.",
                         "examples":  [
                                          {
                                              "en":  "Is the letter written? — Yes, it is. / No, it isn\u0027t.",
                                              "ua":  "Czy list jest napisany? - Tak. / NIE."
                                          },
                                          {
                                              "en":  "Are they invited? — Yes, they are. / No, they aren\u0027t.",
                                              "ua":  "Czy zostali zaproszeni? - Tak. / NIE."
                                          }
                                      ]
                     }
                 ]
}

{
    "title": "5. Aktywny kontra pasywny: czas teraźniejszy prosty",
    "intro": "Porównanie stanu aktywnego i pasywnego:",
    "rows": [
        {
            "en": "Active: Tom writes letters every day.",
            "ua": "Tomek codziennie pisze listy.",
            "note": "→ Passive: Letters are written every day."
        },
        {
            "en": "Active: They clean the rooms daily.",
            "ua": "Codziennie sprzątają pokoje.",
            "note": "→ Passive: The rooms are cleaned daily."
        },
        {
            "en": "Active: People speak English here.",
            "ua": "Ludzie tutaj mówią po angielsku.",
            "note": "→ Passive: English is spoken here."
        }
    ],
    "warning": "📌 Znaczniki czasu (codziennie, zawsze, często) pozostają!"
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zły wybór to/are.",
            "wrong": "The letters is sent every day.",
            "right": "✅ The letters are sent every day."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Pomiń zadawanie pytań.",
            "wrong": "The room cleaned daily?",
            "right": "✅ Is the room cleaned daily?"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Używanie V1 zamiast V3.",
            "wrong": "English is speak here.",
            "right": "✅ English is spoken here."
        }
    ]
}

{
    "title": "Pozostałe strony z podstawami strony biernej",
    "items": [
        {
            "label": "Co to jest głos pasywny?",
            "current": false
        },
        {
            "label": "Forma: być + V3",
            "current": false
        },
        {
            "label": "Present Simple Passive (prąd)",
            "current": true
        },
        {
            "label": "Czas przeszły prosty bierny",
            "current": false
        }
    ]
}
